const rows = ($input.first().json.rows) || [];
let clicks = 0, impressions = 0, posWeighted = 0;
for (const r of rows) {
  clicks += r.clicks;
  impressions += r.impressions;
  posWeighted += r.position * r.impressions;
}
const avgPosition = impressions ? (posWeighted / impressions) : 0;
const topQueries = rows
  .slice()
  .sort((a, b) => (b.clicks - a.clicks) || (b.impressions - a.impressions))
  .slice(0, 5)
  .map(r => r.keys[0]);
const date = $today.minus({ days: 2 }).toFormat('yyyy-MM-dd');
return [{ json: {
  date,
  clicks,
  impressions,
  avgPosition: Math.round(avgPosition * 10) / 10,
  topQueries: topQueries.join(', ')
} }];

const today = $('Aggregate GSC Data').first().json;
const rows = $input.all().map(i => i.json);
// rows are oldest-first; the row we just appended is last, yesterday is second-to-last
const prev = rows.length >= 2 ? rows[rows.length - 2] : null;
const pct = (curr, oldVal) => {
  const o = Number(oldVal);
  if (prev === null || !o) return null;
  return Math.round(((curr - o) / o) * 1000) / 10;
};
return [{ json: {
  ...today,
  clicksChange: pct(today.clicks, prev && prev.clicks),
  imprChange: pct(today.impressions, prev && prev.impressions)
} }];

